mapper.select:
SELECT COUNT(0) "count" FROM T_PRD_WORK_TICKET tpwt
LEFT JOIN T_YARD_TALLY tyt ON TPWT.WORK_PLAN_ID = tyt.PLAN_ID
WHERE tyt.id = #{id}

SELECT ID
FROM M_MACHINE
WHERE MAC_CODE = #{equipmentNo}

SELECT QUANTITY,TON
FROM T_BUS_TRUST_CARGO
WHERE TRUST_ID = #{trustId} and CARGO_INFO_ID = #{cargoInfoId}

SELECT ID
FROM M_STORAGE_YARD
WHERE STORAGE_YARD_NM = #{stackPositionName}

WITH port_storage AS ( SELECT TPPS.CARGO_INFO_ID, sum(tppsd.QUANTITY) quantity, SUM(CASE WHEN tppsd.INOUT_TYPE = '2' THEN tppsd.quantity ELSE 0 end) in_quantity, SUM(CASE WHEN tppsd.INOUT_TYPE = '1' THEN -1*tppsd.quantity ELSE 0 end) out_quantity, sum(tppsd.TON) ton, SUM(CASE WHEN tppsd.INOUT_TYPE = '2' THEN tppsd.ton ELSE 0 end) in_ton, SUM(CASE WHEN tppsd.INOUT_TYPE = '1' THEN -1*tppsd.ton ELSE 0 end) out_ton FROM T_PRD_PORT_STORAGE_DETAIL tppsd , T_PRD_PORT_STORAGE tpps WHERE tppsd.PORT_STORAGE_ID = TPPS.ID(+) GROUP BY TPPS.CARGO_INFO_ID ) SELECT DISTINCT tyt.ID tally_id, tbci.ID CARGO_INFO_ID, tpwp.WORK_DATE , tpwp.CLASS_CODE , tpwp.CLASS_NAME , tbci.CARGO_INFO_NO, port_storage.quantity, port_storage.ton, port_storage.in_quantity, port_storage.in_ton, port_storage.out_quantity, port_storage.out_ton, TYT.QUANTITY tally_quantity, TYT.ton tally_ton, tyt.EQUIPMENT_ID, tyt.EQUIPMENT_NO, tyt.TRANSPORT_EQUIPMENT_ID, tyt.TRANSPORT_EQUIPMENT_NO, tyt.DEPT_ID, tyt.DEPT_NAME, tyt.DEPT_PARENT_ID, tyt.DEPT_PARENT_NAME, source_mass_name, target_mass_name, tyt.CREATE_BY_NAME, tyt.CREATE_TIME FROM T_YARD_TALLY tyt, T_YARD_TALLY_ITEM tyti, T_PRD_WORK_PLAN tpwp, T_BUS_CARGO_INFO tbci, port_storage, (SELECT TALLY_ID, LISTAGG(source_mass_name) WITHIN GROUP (ORDER BY TALLY_ID) source_mass_name, LISTAGG(target_mass_name) WITHIN GROUP (ORDER BY TALLY_ID) target_mass_name FROM ( SELECT TALLY_ID , CASE WHEN tytis.SOURCE_OR_TARGET_FLAG = '1' THEN LISTAGG(STACK_POSITION_NAME) WITHIN GROUP (ORDER BY TALLY_ID) END source_mass_name, CASE WHEN tytis.SOURCE_OR_TARGET_FLAG = '2' THEN LISTAGG(STACK_POSITION_NAME) WITHIN GROUP (ORDER BY TALLY_ID) END target_mass_name FROM T_YARD_TALLY_ITEM tytis LEFT JOIN T_YARD_TALLY tyt ON tyt.id = tytis.TALLY_ID GROUP BY TALLY_ID ,SOURCE_OR_TARGET_FLAG ) GROUP BY TALLY_ID) mass_tally WHERE tyt.PLAN_ID = TPWP.ID(+) AND tyt.ID = tyti.TALLY_ID(+) AND tyti.CARGO_INFO_ID = tbci.ID(+) AND tbci.ID = port_storage.CARGO_INFO_ID(+) AND tyt.id = mass_tally.tally_id AND TYT.DEL_FLAG = 0
AND tyt.PLAN_ID = #{planId}
AND to_char(tpwp.WORK_DATE,'YYYY-MM-DD') = #{workDate}
AND tpwp.CLASS_CODE = #{classCode}
AND tpwp.CLASS_NAME = #{className}
AND tpwp.TRUST_ID = #{trustId}
AND tbci.CARGO_INFO_NO = #{cargoInfoNo}
AND tyt.ID = #{tallyId}

SELECT MAX(STATUS) STATUS FROM T_BUS_CARGO_INFO_COILNUM tbcic
WHERE TBCIC.id IN (
    SELECT COIL_ID FROM T_BUS_TALLY_COILNUM WHERE TALLY_ID = #{tallyId,jdbcType=VARCHAR}
)
